import React, { useState } from 'react';
import './Games.css';

const gameLibrary = [
    {
        id: 'bubble',
        name: "Zen Pop",
        description: "Pop infinite bubbles to release micro-stress. Satisfying audio and haptics included.",
        icon: "🫧",
        category: "Relaxation",
        premium: false
    },
    {
        id: 'breath',
        name: "Neural Flow",
        description: "Synchronize your breathing with a morphing geometric portal.",
        icon: "🌀",
        category: "Focus",
        premium: true
    },
    {
        id: 'match',
        name: "Memory Oasis",
        description: "Flip cards featuring calming nature scenery to improve recall.",
        icon: "🎴",
        category: "Cognitive",
        premium: true
    },
    {
        id: 'rain',
        name: "Rain Maker",
        description: "Create your own lo-fi rain soundscape by tapping different clouds.",
        icon: "🌧️",
        category: "Sleep",
        premium: true
    }
];

function GamesModal({ user, onClose, onUpgradeClick }) {
    const [activeGame, setActiveGame] = useState(null);

    const handlePlay = (game) => {
        if (game.premium && !user.is_premium) {
            onUpgradeClick();
            return;
        }
        setActiveGame(game);
    };

    if (activeGame) {
        return (
            <div className="modal-overlay" onClick={() => setActiveGame(null)}>
                <div className="modal-content game-player-box" onClick={(e) => e.stopPropagation()}>
                    <div className="modal-header">
                        <h2>{activeGame.icon} {activeGame.name}</h2>
                        <button onClick={() => setActiveGame(null)} className="close-btn">×</button>
                    </div>
                    <div className="game-viewport" style={{ height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0f172a', borderRadius: '15px', color: 'white', flexDirection: 'column' }}>
                        <div className="game-placeholder-animation" style={{ fontSize: '50px', marginBottom: '20px' }}>
                           {activeGame.id === 'bubble' ? '🔘 🔘 🔘' : '🧬'}
                        </div>
                        <p>Game Logic Initializing...</p>
                        <button className="game-btn" style={{ width: 'auto', marginTop: '20px' }} onClick={() => setActiveGame(null)}>Exit Game</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content games-modal-container" onClick={(e) => e.stopPropagation()}>
                <div className="modal-header">
                    <div className="games-header">
                        <h2>Arcade Oasis</h2>
                        <p>Scientifically designed mini-games to reset your nervous system.</p>
                    </div>
                    <button onClick={onClose} className="close-btn">×</button>
                </div>
                
                <div className="games-grid">
                    {gameLibrary.map((game) => {
                        const isLocked = game.premium && !user.is_premium;
                        return (
                            <div key={game.id} className="game-card" onClick={() => handlePlay(game)}>
                                {isLocked && <div className="tagline">PREMIUM</div>}
                                <div className="game-thumbnail">
                                    {game.icon}
                                </div>
                                <div className="game-details">
                                    <h3>{game.name}</h3>
                                    <p>{game.description}</p>
                                    <button className={`game-btn ${isLocked ? 'locked' : ''}`}>
                                        {isLocked ? '🔒 Unlock with Premium' : '🎮 Play Now'}
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

export default GamesModal;
